#[pliron_op(
    name = "mir.add",
    format,
    interfaces = [NOpdsInterface<2>, NResultsInterface<1>, OneResultInterface]
)]
pub struct MirAddOp;

impl Verify for MirAddOp {
    fn verify(&self, ctx: &Context) -> Result<(), Error> {
        let op = &*self.get_operation().deref(ctx);
        let lhs = op.get_operand(0);
